Here's a modern MSTest approach using `Task`-returning tests, `[Timeout]`, and cancellation token verification:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private MockHttpMessageHandler _handler = null!;
    private DataFetcher _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _handler = new MockHttpMessageHandler();
        _sut = new DataFetcher(new HttpClient(_handler));
    }

    [TestMethod]
    [Timeout(5000)] // fails test if it hangs
    public async Task FetchAsync_ReturnsContent_WhenResponseIsSuccess()
    {
        _handler.ResponseContent = "hello";
        _handler.StatusCode = HttpStatusCode.OK;

        var result = await _sut.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_Throws_WhenResponseIsNotSuccess()
    {
        _handler.StatusCode = HttpStatusCode.InternalServerError;

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => _sut.FetchAsync("https://example.com"));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ThrowsOperationCanceled_WhenTokenIsCanceled()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel();

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => _sut.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_PassesCancellationToken_ToHttpClient()
    {
        _handler.ResponseContent = "data";
        _handler.StatusCode = HttpStatusCode.OK;

        using var cts = new CancellationTokenSource();
        await _sut.FetchAsync("https://example.com", cts.Token);

        Assert.IsTrue(_handler.ReceivedCancellationToken.CanBeCanceled);
    }

    // Lightweight mock handler — no external mocking library needed
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        public HttpStatusCode StatusCode { get; set; } = HttpStatusCode.OK;
        public string ResponseContent { get; set; } = string.Empty;
        public CancellationToken ReceivedCancellationToken { get; private set; }

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            ReceivedCancellationToken = cancellationToken;

            return Task.FromResult(new HttpResponseMessage(StatusCode)
            {
                Content = new StringContent(ResponseContent)
            });
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | Detail |
|---------|--------|
| `async Task` test methods | MSTest natively awaits them — no `.Result` / `.Wait()` needed |
| `[Timeout(ms)]` | Guards against hanging awaits; fails the test deterministically |
| `Assert.ThrowsExceptionAsync<T>` | Proper async exception assertion (not `try/catch`) |
| Custom `HttpMessageHandler` | Avoids mocking frameworks; gives full control over responses |
| `CancellationToken` forwarding | Verifies the token actually reaches the HTTP layer |

> **MSTest v3+ tip:** If you upgrade to MSTest 3.8+, you can replace `Assert.ThrowsExceptionAsync<T>` with the newer `Assert.ThrowsExactlyAsync<T>` for stricter type matching.
